{
  "module": "01-layout.md",
  "group": "01 — Layout & Container Components",
  "apiCount": 12,
  "apis": [
    {
      "name": "Column",
      "purpose": "垂直方向线性布局容器，可设置子组件间距与对齐方式",
      "anchor": "column",
      "status": "found"
    },
    {
      "name": "Row",
      "purpose": "水平方向线性布局容器，可设置子组件间距与对齐方式",
      "anchor": "row",
      "status": "found"
    },
    {
      "name": "Stack",
      "purpose": "堆叠容器，子组件按顺序依次入栈、后子覆盖前子",
      "anchor": "stack",
      "status": "found"
    },
    {
      "name": "Scroll",
      "purpose": "可滚动容器，子组件超出父组件大小时内容可滚动",
      "anchor": "scroll",
      "status": "found"
    },
    {
      "name": "List",
      "purpose": "列表容器，包含相同宽度的列表项，支持懒加载和多种滚动事件",
      "anchor": "list",
      "status": "found"
    },
    {
      "name": "Text",
      "purpose": "显示文本的组件，支持字体样式、行高、省略、自适应等",
      "anchor": "text",
      "status": "found"
    },
    {
      "name": "Image",
      "purpose": "图片组件，加载本地/网络/像素图并设置填充效果",
      "anchor": "image",
      "status": "found"
    },
    {
      "name": "Blank",
      "purpose": "空白填充组件，在Row/Column/Flex主轴方向自动填充空余空间",
      "anchor": "blank",
      "status": "found"
    },
    {
      "name": "Divider",
      "purpose": "分割线组件，分隔不同内容块，支持水平/垂直方向",
      "anchor": "divider",
      "status": "found"
    },
    {
      "name": "Flex",
      "purpose": "弹性布局容器，高效排列对齐子元素并分配剩余空间",
      "anchor": "flex",
      "status": "found"
    },
    {
      "name": "RelativeContainer",
      "purpose": "相对布局容器，子组件通过alignRules设置以容器或兄弟组件为锚点的对齐规则",
      "anchor": "relativecontainer",
      "status": "found"
    },
    {
      "name": "Swiper",
      "purpose": "滑块视图容器，提供子组件滑动轮播显示能力",
      "anchor": "swiper",
      "status": "found"
    }
  ],
  "notableFindings": [
    "所有12个API均为ArkUI内置组件/容器，无需额外import语句",
    "Column/Row/Flex支持通过space参数或FlexOptions设置子组件间距（API 12+支持FlexSpaceOptions）",
    "RelativeContainer从API version 9开始支持，其余组件从API version 7开始支持",
    "Flex存在二次布局开销，对性能有严格要求的场景建议使用Column/Row替代",
    "Scroll嵌套List时若List不设宽高则默认全量加载懒加载失效，建议指定List宽高",
    "Swiper支持SwiperController控制器进行编程式翻页",
    "RelativeContainer支持guideLine辅助线和barrier屏障（API 12+）",
    "Blank仅在父组件为Row/Column/Flex时生效"
  ],
  "missingApis": []
}

